import 'package:flutter/material.dart';import '../services/api_service.dart';import '../widgets/app_sidebar.dart';
class IntegrationsScreen extends StatefulWidget{const IntegrationsScreen({super.key});@override State<IntegrationsScreen> createState()=>_State();}
class _State extends State<IntegrationsScreen>{final api=ApiService();bool loading=true,saving=false;final host=TextEditingController(),port=TextEditingController(text:'587'),user=TextEditingController(),password=TextEditingController(),from=TextEditingController(),gemini=TextEditingController();bool hasPassword=false,hasGemini=false;@override void initState(){super.initState();load();}@override void dispose(){for(final c in[host,port,user,password,from,gemini])c.dispose();super.dispose();}Future<void> load()async{final d=await api.getIntegrations();host.text=d['smtp_host']?.toString()??'';port.text=d['smtp_port']?.toString()??'587';user.text=d['smtp_user']?.toString()??'';from.text=d['smtp_from_email']?.toString()??'';hasPassword=d['has_smtp_password']==true;hasGemini=d['has_gemini_api_key']==true;if(mounted)setState(()=>loading=false);}Future<void> save()async{setState(()=>saving=true);await api.saveIntegrations({'smtp_host':host.text.trim().isEmpty?null:host.text.trim(),'smtp_port':int.tryParse(port.text),'smtp_user':user.text.trim().isEmpty?null:user.text.trim(),'smtp_password':password.text.trim().isEmpty?null:password.text.trim(),'smtp_from_email':from.text.trim().isEmpty?null:from.text.trim(),'gemini_api_key':gemini.text.trim().isEmpty?null:gemini.text.trim()});password.clear();gemini.clear();await load();if(mounted){setState(()=>saving=false);ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content:Text('Integration settings saved.')));}}Widget field(TextEditingController c,String label,{bool secret=false,TextInputType? keyboard})=>Padding(padding:const EdgeInsets.only(bottom:12),child:TextField(controller:c,obscureText:secret,keyboardType:keyboard,decoration:InputDecoration(labelText:label,border:const OutlineInputBorder())));@override Widget build(BuildContext context)=>Scaffold(drawer:const AppSidebar(role:'trainer'),appBar:AppBar(title:const Text('Email & AI Settings')),body:loading?const Center(child:CircularProgressIndicator()):ListView(padding:const EdgeInsets.all(24),children:[Text('SMTP email',style:Theme.of(context).textTheme.headlineSmall),const Text('Used for password resets, reminders, and completion emails.'),const SizedBox(height:12),field(host,'SMTP host'),field(port,'SMTP port',keyboard:TextInputType.number),field(user,'SMTP username'),field(password,hasPassword?'SMTP password (leave blank to keep existing)':'SMTP password',secret:true),field(from,'From email'),const SizedBox(height:20),Text('Gemini AI',style:Theme.of(context).textTheme.headlineSmall),field(gemini,hasGemini?'Gemini API key (leave blank to keep existing)':'Gemini API key',secret:true),Align(alignment:Alignment.centerRight,child:FilledButton.icon(onPressed:saving?null:save,icon:const Icon(Icons.save),label:Text(saving?'Saving…':'Save settings'))]));}
